# pyre-strict

"""Tests for ``type_system_digest.py`` -- the cross-language-identical SHA-256
digest over the canonical ``SerializableTypeSystem``.

Golden parity is validated against the C++ reference values in
``thrift/lib/cpp2/dynamic/test/digest_expected_values.thrift`` (snapshotted below),
both via hand-built / programmatic type systems (no bridge) and via the
``SchemaRegistry`` bridge on real loaded Python modules.
"""

import hashlib
import struct
import unittest

# Importing the fixture modules makes their URIs discoverable by the registry.
import apache.thrift.type_system.test.digest_fixture_enum.thrift_types  # noqa: F401
import apache.thrift.type_system.test.digest_fixture_single_empty_struct.thrift_types  # noqa: F401
import apache.thrift.type_system.test.digest_fixture_struct_with_fields.thrift_types  # noqa: F401
import thrift.lib.python.schema.tests.type_system_bridge_test.thrift_types  # noqa: F401
from apache.thrift.type_system.record.thrift_types import (
    SerializableRecord as WireRecord,
)

# The golden DIGEST_* constants are the cross-language source of truth, imported
# from digest_expected_values.thrift (generated by the C++ TypeSystemDigest
# implementation).
from apache.thrift.type_system.test.digest_expected_values.thrift_types import (
    DIGEST_EMPTY,
    DIGEST_ENUM,
    DIGEST_MULTIPLE_TYPES,
    DIGEST_SINGLE_EMPTY_STRUCT,
    DIGEST_STRUCT_WITH_FIELDS,
    DIGEST_TYPE_ID_BOOL,
    DIGEST_TYPE_ID_I32,
    DIGEST_TYPE_ID_STRING,
    DIGEST_TYPE_ID_URI,
)
from apache.thrift.type_system.type_id.thrift_types import (
    DoubleTypeId,
    I32TypeId,
    I64TypeId,
    ListTypeId,
    TypeId,
)
from apache.thrift.type_system.type_system.thrift_types import (
    FieldIdentity as WireFieldIdentity,
    PresenceQualifier as WirePresence,
    SerializableFieldDefinition,
    SerializableStructDefinition,
    SerializableThriftSourceInfo,
    SerializableTypeDefinition,
    SerializableTypeDefinitionEntry,
    SerializableTypeSystem,
)
from thrift.lib.python.schema._serializable import (
    build_serializable_type_system,
    to_type_id,
)
from thrift.lib.python.schema.schema_registry import SchemaRegistry
from thrift.lib.python.schema.type_system import (
    EnumValue,
    FieldIdentity,
    IndexedTypeSystem,
    PresenceQualifier,
    Primitive,
    PrimitiveTypeRef,
    StructNode,
    TypeRef,
    TypeSystem,
)
from thrift.lib.python.schema.type_system_builder import FieldSpec, TypeSystemBuilder
from thrift.lib.python.schema.type_system_digest import (
    DigestMode,
    type_id_digest,
    type_system_digest,
    TYPE_SYSTEM_DIGEST_VERSION,
)

_BRIDGE_URI = "thrift.com/python/schema/ts_bridge"
_I32_ID = TypeId(i32Type=I32TypeId())


# --- helpers -----------------------------------------------------------------
def _field(
    field_id: int,
    name: str,
    type_ref: TypeRef,
    presence: PresenceQualifier = PresenceQualifier.UNQUALIFIED,
) -> FieldSpec:
    return FieldSpec(FieldIdentity(field_id, name), presence, type_ref)


def _i32() -> PrimitiveTypeRef:
    return PrimitiveTypeRef(Primitive.I32)


def _digest_of(
    source: TypeSystem, roots: list[str], mode: DigestMode = DigestMode.FULL
) -> bytes:
    """Digest of a runtime type system, exported root-pruned to the wire form."""
    return type_system_digest(build_serializable_type_system(source, roots), mode)


def _wire_struct_sts(
    *fields: SerializableFieldDefinition,
    uri: str = "test/Foo",
    is_sealed: bool = False,
    source_info: SerializableThriftSourceInfo | None = None,
) -> SerializableTypeSystem:
    """A one-struct wire ``SerializableTypeSystem`` (for record-level tests that
    the programmatic builder can't express, e.g. custom defaults)."""
    return SerializableTypeSystem(
        types={
            uri: SerializableTypeDefinitionEntry(
                definition=SerializableTypeDefinition(
                    structDef=SerializableStructDefinition(
                        fields=list(fields), isSealed=is_sealed, annotations={}
                    )
                ),
                sourceInfo=source_info,
            )
        }
    )


def _wire_field_with_default(default: WireRecord) -> SerializableFieldDefinition:
    return SerializableFieldDefinition(
        identity=WireFieldIdentity(id=1, name="f"),
        presence=WirePresence.UNQUALIFIED,
        type=_I32_ID,
        customDefaultPartialRecord=default,
        annotations={},
    )


# Manual little-endian encoders, mirroring the canonical wire format. Used to
# lock the exact byte layout for cases the C++ goldens don't cover (floats, the
# record id-4 gap, None container children).
def _u8(v: int) -> bytes:
    return struct.pack("<B", v)


def _i16(v: int) -> bytes:
    return struct.pack("<h", v)


def _i32b(v: int) -> bytes:
    return struct.pack("<i", v)


def _u32(v: int) -> bytes:
    return struct.pack("<I", v)


def _f64(v: float) -> bytes:
    return struct.pack("<d", v)


def _i8(v: int) -> bytes:
    return struct.pack("<b", v)


def _i64(v: int) -> bytes:
    return struct.pack("<q", v)


def _f32(v: float) -> bytes:
    return struct.pack("<f", v)


def _s(text: str) -> bytes:
    b = text.encode("utf-8")
    return _u32(len(b)) + b


def _sha(b: bytes) -> bytes:
    return hashlib.sha256(b).digest()


def _struct_with_default_digest(record_bytes: bytes) -> bytes:
    """Expected digest of ``_wire_struct_sts(_wire_field_with_default(<record>))``.

    Mirrors the canonical layout: version + uri("test/Foo") + structDef(1) +
    [single field: i16 id(1) + name("f") + i32 presence(UNQUALIFIED) +
    TypeId(i32Type=4) + <record_bytes> + annotations(0)] + isSealed(0) +
    annotations(0). ``record_bytes`` is the field's custom-default record
    (discriminant + payload), supplied by each test."""
    field = (
        _i16(1)
        + _s("f")
        + _i32b(PresenceQualifier.UNQUALIFIED.value)
        + _i32b(4)  # TypeId i32Type discriminant (from _wire_field_with_default)
        + record_bytes
        + _u32(0)  # field annotations (empty)
    )
    struct_body = _i32b(1) + field + _u8(0) + _u32(0)
    return _sha(_u8(2) + _s("test/Foo") + struct_body)


class VersionTest(unittest.TestCase):
    def test_version_constant_is_two(self) -> None:
        self.assertEqual(TYPE_SYSTEM_DIGEST_VERSION, 2)

    def test_empty_type_system_is_version_byte_only(self) -> None:
        # An empty type system hashes exactly the single version byte -- proving
        # the version is hashed first and nothing else is emitted.
        digest = type_system_digest(SerializableTypeSystem(types={}))
        self.assertEqual(digest, _sha(_u8(2)))
        self.assertEqual(digest.hex(), DIGEST_EMPTY)


class GoldenParityTest(unittest.TestCase):
    """Byte-identical to the C++ reference, built without the SyntaxGraph bridge."""

    def test_single_empty_struct(self) -> None:
        ts = TypeSystemBuilder().add_struct("meta.com/test/Empty", []).build()
        self.assertEqual(
            _digest_of(ts, ["meta.com/test/Empty"]).hex(), DIGEST_SINGLE_EMPTY_STRUCT
        )

    def test_struct_with_fields(self) -> None:
        ts = (
            TypeSystemBuilder()
            .add_struct(
                "meta.com/test/Person",
                [
                    _field(1, "name", PrimitiveTypeRef(Primitive.STRING)),
                    _field(2, "age", _i32(), PresenceQualifier.OPTIONAL),
                ],
            )
            .build()
        )
        self.assertEqual(
            _digest_of(ts, ["meta.com/test/Person"]).hex(), DIGEST_STRUCT_WITH_FIELDS
        )

    def test_enum(self) -> None:
        ts = (
            TypeSystemBuilder()
            .add_enum(
                "meta.com/test/Status",
                [
                    EnumValue("ACTIVE", 1),
                    EnumValue("INACTIVE", 2),
                    EnumValue("PENDING", 3),
                ],
            )
            .build()
        )
        self.assertEqual(_digest_of(ts, ["meta.com/test/Status"]).hex(), DIGEST_ENUM)

    def test_multiple_types(self) -> None:
        # Person + Status + an opaque alias UserId -> i64 (not IDL-expressible).
        ts = (
            TypeSystemBuilder()
            .add_struct(
                "meta.com/test/multi/Person",
                [
                    _field(1, "name", PrimitiveTypeRef(Primitive.STRING)),
                    _field(2, "age", _i32(), PresenceQualifier.OPTIONAL),
                ],
            )
            .add_enum(
                "meta.com/test/multi/Status",
                [EnumValue("ACTIVE", 1), EnumValue("INACTIVE", 2)],
            )
            .add_opaque_alias(
                "meta.com/test/multi/UserId", PrimitiveTypeRef(Primitive.I64)
            )
            .build()
        )
        roots = [
            "meta.com/test/multi/Person",
            "meta.com/test/multi/Status",
            "meta.com/test/multi/UserId",
        ]
        self.assertEqual(_digest_of(ts, roots).hex(), DIGEST_MULTIPLE_TYPES)

    def test_type_id_bool(self) -> None:
        self.assertEqual(
            type_id_digest(to_type_id(PrimitiveTypeRef(Primitive.BOOL))).hex(),
            DIGEST_TYPE_ID_BOOL,
        )

    def test_type_id_i32(self) -> None:
        self.assertEqual(type_id_digest(to_type_id(_i32())).hex(), DIGEST_TYPE_ID_I32)

    def test_type_id_string(self) -> None:
        self.assertEqual(
            type_id_digest(to_type_id(PrimitiveTypeRef(Primitive.STRING))).hex(),
            DIGEST_TYPE_ID_STRING,
        )

    def test_type_id_uri(self) -> None:
        self.assertEqual(
            type_id_digest(TypeId(userDefinedType="meta.com/test/MyStruct")).hex(),
            DIGEST_TYPE_ID_URI,
        )


class OrderingTest(unittest.TestCase):
    """Canonical ordering: types by URI, fields by id, enum values by datum,
    fieldSetDatum by field id."""

    def test_top_level_sorted_by_uri(self) -> None:
        ts = (
            TypeSystemBuilder()
            .add_struct("test/A", [_field(1, "x", _i32())])
            .add_struct("test/B", [_field(1, "y", _i32())])
            .build()
        )
        # Different root orderings drive different closure-insertion orders, but
        # the digest sorts top-level types by URI.
        self.assertEqual(
            _digest_of(ts, ["test/A", "test/B"]),
            _digest_of(ts, ["test/B", "test/A"]),
        )

    def test_struct_fields_sorted_by_id(self) -> None:
        out_of_order = (
            TypeSystemBuilder()
            .add_struct("test/S", [_field(2, "b", _i32()), _field(1, "a", _i32())])
            .build()
        )
        in_order = (
            TypeSystemBuilder()
            .add_struct("test/S", [_field(1, "a", _i32()), _field(2, "b", _i32())])
            .build()
        )
        self.assertEqual(
            _digest_of(out_of_order, ["test/S"]), _digest_of(in_order, ["test/S"])
        )

    def test_enum_values_sorted_by_datum(self) -> None:
        out_of_order = (
            TypeSystemBuilder()
            .add_enum("test/E", [EnumValue("B", 2), EnumValue("A", 1)])
            .build()
        )
        in_order = (
            TypeSystemBuilder()
            .add_enum("test/E", [EnumValue("A", 1), EnumValue("B", 2)])
            .build()
        )
        self.assertEqual(
            _digest_of(out_of_order, ["test/E"]), _digest_of(in_order, ["test/E"])
        )

    def test_field_set_datum_sorted_by_field_id(self) -> None:
        forward = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    fieldSetDatum={
                        1: WireRecord(boolDatum=True),
                        2: WireRecord(int32Datum=20),
                    }
                )
            )
        )
        reverse = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    fieldSetDatum={
                        2: WireRecord(int32Datum=20),
                        1: WireRecord(boolDatum=True),
                    }
                )
            )
        )
        self.assertEqual(type_system_digest(forward), type_system_digest(reverse))


class UnorderedCollectionTest(unittest.TestCase):
    """Sets / maps / annotation maps are order-independent (per-element subdigest,
    u32 count prefix, lexicographically-sorted subdigests)."""

    def test_set_datum_order_independent(self) -> None:
        a = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    setDatum=[WireRecord(int32Datum=1), WireRecord(int32Datum=2)]
                )
            )
        )
        b = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    setDatum=[WireRecord(int32Datum=2), WireRecord(int32Datum=1)]
                )
            )
        )
        self.assertEqual(type_system_digest(a), type_system_digest(b))

    def test_map_datum_order_independent(self) -> None:
        from apache.thrift.type_system.record.thrift_types import (
            SerializableRecordMapEntry,
        )

        def _entry(k: int, v: int) -> SerializableRecordMapEntry:
            return SerializableRecordMapEntry(
                key=WireRecord(int32Datum=k), value=WireRecord(int32Datum=v)
            )

        a = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(mapDatum=[_entry(1, 10), _entry(2, 20)])
            )
        )
        b = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(mapDatum=[_entry(2, 20), _entry(1, 10)])
            )
        )
        self.assertEqual(type_system_digest(a), type_system_digest(b))

    def test_list_datum_order_dependent(self) -> None:
        # A list preserves order, so a permutation MUST change the digest.
        a = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    listDatum=[WireRecord(int32Datum=1), WireRecord(int32Datum=2)]
                )
            )
        )
        b = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    listDatum=[WireRecord(int32Datum=2), WireRecord(int32Datum=1)]
                )
            )
        )
        self.assertNotEqual(type_system_digest(a), type_system_digest(b))

    def test_annotation_map_order_independent(self) -> None:
        anno_a = StructNode(uri="test/AnnoA", fields=[])
        anno_b = StructNode(uri="test/AnnoB", fields=[])
        from thrift.lib.python.schema._record import FieldSetRecord

        def _foo(anns: dict[str, object]) -> StructNode:
            # pyre-ignore[6]: annotations are SerializableRecord values
            return StructNode(uri="test/Foo", fields=[], annotations=anns)

        rec_a = FieldSetRecord({})
        rec_b = FieldSetRecord({})
        src1 = IndexedTypeSystem(
            {
                "test/AnnoA": anno_a,
                "test/AnnoB": anno_b,
                "test/Foo": _foo({"test/AnnoA": rec_a, "test/AnnoB": rec_b}),
            }
        )
        src2 = IndexedTypeSystem(
            {
                "test/AnnoA": anno_a,
                "test/AnnoB": anno_b,
                "test/Foo": _foo({"test/AnnoB": rec_b, "test/AnnoA": rec_a}),
            }
        )
        self.assertEqual(_digest_of(src1, ["test/Foo"]), _digest_of(src2, ["test/Foo"]))


class EncodingTest(unittest.TestCase):
    """Lock the exact wire encoding for cases the C++ goldens don't exercise."""

    def test_float64_default_bit_layout(self) -> None:
        sts = SerializableTypeSystem(
            types={
                "test/Foo": SerializableTypeDefinitionEntry(
                    definition=SerializableTypeDefinition(
                        structDef=SerializableStructDefinition(
                            fields=[
                                SerializableFieldDefinition(
                                    identity=WireFieldIdentity(id=1, name="f"),
                                    presence=WirePresence.UNQUALIFIED,
                                    type=TypeId(doubleType=DoubleTypeId()),
                                    customDefaultPartialRecord=WireRecord(
                                        float64Datum=1.5
                                    ),
                                    annotations={},
                                )
                            ],
                            isSealed=False,
                            annotations={},
                        )
                    )
                )
            }
        )
        # version + uri + structDef(1) + [field] + isSealed(0) + annotations(0)
        # field = i16 id + name + i32 presence + TypeId(double=7)
        #         + record[float64Datum disc 8 + f64 bits LE] + annotations(0)
        field = (
            _i16(1)
            + _s("f")
            + _i32b(PresenceQualifier.UNQUALIFIED.value)
            + _i32b(7)  # TypeId doubleType discriminant
            + (_i32b(8) + _f64(1.5))  # float64Datum discriminant + IEEE-754 bits
            + _u32(0)
        )
        struct_body = _i32b(1) + field + _u8(0) + _u32(0)
        expected = _sha(_u8(2) + _s("test/Foo") + struct_body)
        self.assertEqual(type_system_digest(sts), expected)


class DiscriminantTest(unittest.TestCase):
    def test_struct_and_union_discriminants_differ(self) -> None:
        # struct=1 vs union=2: identical fields must produce different digests.
        struct_ts = (
            TypeSystemBuilder()
            .add_struct("test/X", [_field(1, "a", _i32(), PresenceQualifier.OPTIONAL)])
            .build()
        )
        union_ts = (
            TypeSystemBuilder()
            .add_union("test/X", [_field(1, "a", _i32(), PresenceQualifier.OPTIONAL)])
            .build()
        )
        self.assertNotEqual(
            _digest_of(struct_ts, ["test/X"]), _digest_of(union_ts, ["test/X"])
        )

    def test_record_field_id_gap_at_four(self) -> None:
        # int32Datum is thrift field 5 (field 4 is unused in record.thrift); the
        # record discriminant must be 5, not 4.
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(int32Datum=42)))
        field = (
            _i16(1)
            + _s("f")
            + _i32b(PresenceQualifier.UNQUALIFIED.value)
            + _i32b(4)  # TypeId i32Type discriminant
            + (_i32b(5) + _i32b(42))  # int32Datum discriminant is 5 (gap at 4)
            + _u32(0)
        )
        struct_body = _i32b(1) + field + _u8(0) + _u32(0)
        expected = _sha(_u8(2) + _s("test/Foo") + struct_body)
        self.assertEqual(type_system_digest(sts), expected)

    def test_type_id_none_container_child_is_zero_byte(self) -> None:
        # A list TypeId with an absent element child: list disc 12 + a single 0u8.
        type_id = TypeId(listType=ListTypeId(elementType=None))
        self.assertEqual(type_id_digest(type_id), _sha(_i32b(12) + _u8(0)))


class SourceInfoTest(unittest.TestCase):
    def test_source_info_excluded(self) -> None:
        without = _wire_struct_sts(
            _wire_field_with_default(WireRecord(int32Datum=1)), source_info=None
        )
        with_info = _wire_struct_sts(
            _wire_field_with_default(WireRecord(int32Datum=1)),
            source_info=SerializableThriftSourceInfo(
                locator="file://x.thrift", name="Foo"
            ),
        )
        self.assertEqual(type_system_digest(without), type_system_digest(with_info))


class CrossLanguageBridgeTest(unittest.TestCase):
    """The full registry bridge -> export -> digest path on real loaded modules
    matches the C++ golden values."""

    def setUp(self) -> None:
        SchemaRegistry._reset()
        self.registry = SchemaRegistry()

    def tearDown(self) -> None:
        SchemaRegistry._reset()

    def test_empty_struct_matches_cpp(self) -> None:
        self.assertEqual(
            self.registry.type_system_digest(["meta.com/test/Empty"]).hex(),
            DIGEST_SINGLE_EMPTY_STRUCT,
        )

    def test_struct_with_fields_matches_cpp(self) -> None:
        self.assertEqual(
            self.registry.type_system_digest(["meta.com/test/Person"]).hex(),
            DIGEST_STRUCT_WITH_FIELDS,
        )

    def test_enum_matches_cpp(self) -> None:
        self.assertEqual(
            self.registry.type_system_digest(["meta.com/test/Status"]).hex(),
            DIGEST_ENUM,
        )


class TerseDigestParityTest(unittest.TestCase):
    """Terse fields: the bridge preserves TERSE presence (unlike the C++
    SyntaxGraph facade), so its digest matches the canonical builder value with
    TERSE -- and differs from one that collapses terse to unqualified."""

    def setUp(self) -> None:
        SchemaRegistry._reset()
        self.registry = SchemaRegistry()

    def tearDown(self) -> None:
        SchemaRegistry._reset()

    def _presence_uri(self) -> str:
        return f"{_BRIDGE_URI}/Presence"

    def _builder_presence(self, terse_presence: PresenceQualifier) -> TypeSystem:
        return (
            TypeSystemBuilder()
            .add_struct(
                self._presence_uri(),
                [
                    _field(1, "plain", _i32(), PresenceQualifier.UNQUALIFIED),
                    _field(2, "maybe", _i32(), PresenceQualifier.OPTIONAL),
                    _field(3, "terse", _i32(), terse_presence),
                ],
            )
            .build()
        )

    def test_bridge_matches_canonical_terse(self) -> None:
        uri = self._presence_uri()
        bridge_digest = self.registry.type_system_digest([uri])
        canonical = self._builder_presence(PresenceQualifier.TERSE)
        self.assertEqual(bridge_digest, _digest_of(canonical, [uri]))

    def test_bridge_differs_from_terse_dropping(self) -> None:
        uri = self._presence_uri()
        bridge_digest = self.registry.type_system_digest([uri])
        # A facade that collapses terse->unqualified would produce this digest.
        dropped = self._builder_presence(PresenceQualifier.UNQUALIFIED)
        self.assertNotEqual(bridge_digest, _digest_of(dropped, [uri]))


class ScalarRecordEncodingTest(unittest.TestCase):
    """Byte-layout of each scalar custom-default record arm."""

    def test_bool_datum(self) -> None:
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(boolDatum=True)))
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(1) + b"\x01"),
        )

    def test_int8_datum(self) -> None:
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(int8Datum=-5)))
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(2) + _i8(-5)),
        )

    def test_int16_datum(self) -> None:
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(int16Datum=-1000)))
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(3) + _i16(-1000)),
        )

    def test_int64_datum(self) -> None:
        # A value beyond int32 range proves the arm hashes a full 8-byte i64.
        sts = _wire_struct_sts(
            _wire_field_with_default(WireRecord(int64Datum=9999999999))
        )
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(6) + _i64(9999999999)),
        )

    def test_float32_datum(self) -> None:
        # 1.5 is exactly representable in single precision; the arm packs 4 bytes.
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(float32Datum=1.5)))
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(7) + _f32(1.5)),
        )

    def test_text_datum(self) -> None:
        sts = _wire_struct_sts(_wire_field_with_default(WireRecord(textDatum="hi")))
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(9) + _s("hi")),
        )

    def test_byte_array_datum(self) -> None:
        # byteArrayDatum is a folly IOBuf in thrift-python; the hasher flattens it
        # and emits a u32 length prefix + raw bytes. This path is exercised nowhere
        # else, so a length-width or flatten regression would otherwise slip by.
        from folly.iobuf import IOBuf

        sts = _wire_struct_sts(
            _wire_field_with_default(WireRecord(byteArrayDatum=IOBuf(b"binary")))
        )
        self.assertEqual(
            type_system_digest(sts),
            _struct_with_default_digest(_i32b(10) + _u32(len(b"binary")) + b"binary"),
        )


class ContainerRecordEncodingTest(unittest.TestCase):
    """Byte-layout of container custom-default record arms."""

    @staticmethod
    def _i32_record(v: int) -> bytes:
        # A single int32Datum record: discriminant 5 + i32 payload.
        return _i32b(5) + _i32b(v)

    def test_list_datum_concatenates_without_count(self) -> None:
        sts = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    listDatum=[WireRecord(int32Datum=1), WireRecord(int32Datum=2)]
                )
            )
        )
        record = _i32b(12) + self._i32_record(1) + self._i32_record(2)
        self.assertEqual(type_system_digest(sts), _struct_with_default_digest(record))

    def test_set_datum_count_plus_sorted_subdigests(self) -> None:
        sts = _wire_struct_sts(
            _wire_field_with_default(WireRecord(setDatum=[WireRecord(int32Datum=7)]))
        )
        # u32 count(1) + the 32-byte sub-digest of the single element record.
        record = _i32b(13) + _u32(1) + _sha(self._i32_record(7))
        self.assertEqual(type_system_digest(sts), _struct_with_default_digest(record))

    def test_map_datum_count_plus_full_entries(self) -> None:
        from apache.thrift.type_system.record.thrift_types import (
            SerializableRecordMapEntry,
        )

        sts = _wire_struct_sts(
            _wire_field_with_default(
                WireRecord(
                    mapDatum=[
                        SerializableRecordMapEntry(
                            key=WireRecord(int32Datum=1),
                            value=WireRecord(int32Datum=10),
                        )
                    ]
                )
            )
        )
        # u32 count(1) + full key record + full value record (NOT a sub-digest).
        record = _i32b(14) + _u32(1) + self._i32_record(1) + self._i32_record(10)
        self.assertEqual(type_system_digest(sts), _struct_with_default_digest(record))


class ScalarDispatchGuardTest(unittest.TestCase):
    def test_unhandled_scalar_arm_raises(self) -> None:
        from thrift.lib.python.schema.type_system import InvalidTypeError
        from thrift.lib.python.schema.type_system_digest import (
            _hash_scalar_record,
            _Hasher,
        )

        container = WireRecord(listDatum=[WireRecord(int32Datum=1)])
        with self.assertRaises(InvalidTypeError):
            _hash_scalar_record(_Hasher(), WireRecord.Type.listDatum, container)


class StructuralModeTest(unittest.TestCase):
    """``DigestMode.STRUCTURAL`` hashes only the wire structure, skipping
    annotations and custom default values.

    There are no cross-language golden values for the structural digest (the C++
    fixture snapshots ``Full`` only), so parity is locked by an exact byte-layout
    assertion plus the same property assertions the C++ suite uses."""

    @staticmethod
    def _field(
        *,
        type_id: TypeId,
        default: WireRecord | None = None,
        annotations: dict[str, WireRecord] | None = None,
    ) -> SerializableFieldDefinition:
        return SerializableFieldDefinition(
            identity=WireFieldIdentity(id=1, name="f"),
            presence=WirePresence.UNQUALIFIED,
            type=type_id,
            customDefaultPartialRecord=default,
            annotations=annotations or {},
        )

    @classmethod
    def _struct_sts(
        cls,
        field: SerializableFieldDefinition,
        struct_annotations: dict[str, WireRecord] | None = None,
    ) -> SerializableTypeSystem:
        return SerializableTypeSystem(
            types={
                "test/Foo": SerializableTypeDefinitionEntry(
                    definition=SerializableTypeDefinition(
                        structDef=SerializableStructDefinition(
                            fields=[field],
                            isSealed=False,
                            annotations=struct_annotations or {},
                        )
                    )
                )
            }
        )

    def _annotated(self) -> SerializableTypeSystem:
        # struct-level annotation + a field carrying both a custom default and a
        # field-level annotation.
        return self._struct_sts(
            self._field(
                type_id=_I32_ID,
                default=WireRecord(int32Datum=42),
                annotations={"meta.com/FAnn": WireRecord(fieldSetDatum={})},
            ),
            struct_annotations={"meta.com/SAnn": WireRecord(fieldSetDatum={})},
        )

    def _bare(self) -> SerializableTypeSystem:
        return self._struct_sts(self._field(type_id=_I32_ID))

    def test_full_is_the_default_mode(self) -> None:
        annotated = self._annotated()
        self.assertEqual(
            type_system_digest(annotated),
            type_system_digest(annotated, DigestMode.FULL),
        )

    def test_structural_ignores_annotations_and_defaults(self) -> None:
        annotated = self._annotated()
        bare = self._bare()
        # Full reflects annotations and custom defaults...
        self.assertNotEqual(type_system_digest(annotated), type_system_digest(bare))
        # ...while structural ignores them.
        self.assertEqual(
            type_system_digest(annotated, DigestMode.STRUCTURAL),
            type_system_digest(bare, DigestMode.STRUCTURAL),
        )

    def test_structural_still_distinguishes_structure(self) -> None:
        # A genuine wire difference (field type) must still change the digest.
        i32 = self._bare()
        i64 = self._struct_sts(self._field(type_id=TypeId(i64Type=I64TypeId())))
        self.assertNotEqual(
            type_system_digest(i32, DigestMode.STRUCTURAL),
            type_system_digest(i64, DigestMode.STRUCTURAL),
        )

    def test_structural_byte_layout_omits_annotations_and_defaults(self) -> None:
        # The strongest parity guarantee: the structural digest of the annotated
        # struct equals a manual layout that omits the custom default AND every
        # annotation -- with NO u32 count prefix for the skipped annotations.
        field = (
            _i16(1)
            + _s("f")
            + _i32b(PresenceQualifier.UNQUALIFIED.value)
            + _i32b(4)  # TypeId i32Type discriminant; no default, no annotations
        )
        struct_body = _i32b(1) + field + _u8(0)  # structDef disc, field, isSealed
        expected = _sha(_u8(2) + _s("test/Foo") + struct_body)
        self.assertEqual(
            type_system_digest(self._annotated(), DigestMode.STRUCTURAL), expected
        )


class RegistryStructuralModeTest(unittest.TestCase):
    """The ``SchemaRegistry`` wrapper threads the mode through to the canonical
    digest, matching the builder-produced structural digest."""

    def setUp(self) -> None:
        SchemaRegistry._reset()
        self.registry = SchemaRegistry()

    def tearDown(self) -> None:
        SchemaRegistry._reset()

    def test_registry_threads_structural_mode(self) -> None:
        roots = ["meta.com/test/Person"]
        builder_person = (
            TypeSystemBuilder()
            .add_struct(
                "meta.com/test/Person",
                [
                    _field(1, "name", PrimitiveTypeRef(Primitive.STRING)),
                    _field(2, "age", _i32(), PresenceQualifier.OPTIONAL),
                ],
            )
            .build()
        )
        self.assertEqual(
            self.registry.type_system_digest(roots, DigestMode.STRUCTURAL),
            _digest_of(builder_person, roots, DigestMode.STRUCTURAL),
        )
        # And structural differs from full even here (full emits empty-annotation
        # count prefixes that structural omits).
        self.assertNotEqual(
            self.registry.type_system_digest(roots, DigestMode.STRUCTURAL),
            self.registry.type_system_digest(roots),
        )


if __name__ == "__main__":
    unittest.main()
